mapper.select:
select ifnull(avg(msg_count), 0) from (
    select session_id, count(*) as msg_count from ai_message group by session_id
) t

select content as question, count(*) as cnt
from ai_message where role = 'user'
group by content order by cnt desc limit #{limit}

select hour(create_time) as h, count(*) as cnt
from ai_message where role = 'user' and date(create_time) = curdate()
group by hour(create_time) order by h
